import { Anthropic } from '@anthropic-ai/sdk';
import { Vex } from 'vex-sdk';

const anthropic = new Anthropic({ apiKey: 'your-key' });
const vex = new Vex({ apiKey: 'your-vex-key' });

async function processClaim(claimId: string) {
  const message = await anthropic.messages.create({
    model: 'claude-3-5-sonnet-20240620',
    max_tokens: 1024,
    tools: [
      { name: 'analyze_damage_photos', type: 'function', inputSchema: { type: 'object', properties: { claimId: { type: 'string' } } } },
      { name: 'check_policy_coverage', type: 'function', inputSchema: { type: 'object', properties: { claimId: { type: 'string' } } } }
    ],
    messages: [{ role: 'user', content: `Process claim ${claimId}` }]
  });

  // Verify parallel tool consistency
  const verified = await vex.verify({
    input: message,
    spec: {
      'tool_conflict_resolution': true,
      'explainable_denial': true,
      'no_pii_leakage': true
    },
    metadata: { regulation: 'NAIC', useCase: 'claims_processing' }
  });

  if (verified.passed) {
    console.log('Approved:', message.content[0].text);
  } else {
    console.error('Blocked:', verified.violations);
  }
}

import anthropic
import vex

# Install: pip install anthropic vex-sdk
client = anthropic.Anthropic()
vex_client = vex.Client()

def safe_computer_use(session_id: str):
    # Claude computer use for insurance doc processing
    response = client.messages.create(
        model="claude-3-opus-20240229",
        messages=[{
            "role": "user",
            "content": "Extract coverage limits from policy PDF on screen"
        }],
        tools=[{"type": "computer_use"}]  # Hypothetical computer use tool
    )

    # Vex audits screen actions
    audit = vex_client.verify(
        response,
        spec={
            "no_pii_screenshots": True,
            "audited_access": True,
            "encrypted_logs": True
        },
        context={"action_type": "screen_interaction", "data_class": "policyholder_pii"}
    )

    return audit.passed, response.content
